{
  "name": "AL 2026 Countdown & Success Hub",
  "description": "A comprehensive countdown and study companion for GCE A/L 2026 candidates, featuring real-time timers, Gemini-powered study advice, and subject progress tracking."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TimeLeft {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
}

export interface Subject {
  id: string;
  name: string;
  progress: number;
  color: string;
}

export interface GeminiAdvice {
  title: string;
  content: string;
  category: 'motivation' | 'study-tip' | 'exam-strategy';
}

// Tentative start date for GCE A/L 2026
// Typically held late in the year in Sri Lanka (e.g., late November)
export const EXAM_DATE = new Date('2026-11-23T08:30:00');

export const INITIAL_SUBJECTS = [
  { id: '1', name: 'Physics / Accounting', progress: 0, color: 'bg-blue-500' },
  { id: '2', name: 'Chemistry / Economics', progress: 0, color: 'bg-emerald-500' },
  { id: '3', name: 'Combined Maths / Business Studies', progress: 0, color: 'bg-purple-500' },
  { id: '4', name: 'General English', progress: 0, color: 'bg-amber-500' },
];

export const CATEGORY_ICONS: Record<string, string> = {
  motivation: '🔥',
  'study-tip': '📚',
  'exam-strategy': '🎯'
};

import { GoogleGenAI, Type } from "@google/genai";
import { GeminiAdvice } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getDailyAdvice = async (daysRemaining: number): Promise<GeminiAdvice> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `The student has ${daysRemaining} days remaining for their GCE Advanced Level (A/L) 2026 examination. Provide a short, highly motivating, and practical piece of advice.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            category: { 
              type: Type.STRING,
              enum: ['motivation', 'study-tip', 'exam-strategy']
            }
          },
          required: ["title", "content", "category"]
        }
      },
    });

    return JSON.parse(response.text.trim()) as GeminiAdvice;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      title: "Keep Pushing Forward!",
      content: "Consistency is the key to mastering A/L. Small daily steps lead to massive success in 2026.",
      category: "motivation"
    };
  }
};

import React from 'react';
import { TimeLeft } from '../types';

interface CountdownCardProps {
  timeLeft: TimeLeft;
}

const CountdownCard: React.FC<CountdownCardProps> = ({ timeLeft }) => {
  const Unit: React.FC<{ value: number; label: string }> = ({ value, label }) => (
    <div className="flex flex-col items-center justify-center p-4 md:p-6 glass-card rounded-2xl min-w-[80px] md:min-w-[120px] transition-transform hover:scale-105">
      <span className="text-3xl md:text-5xl font-extrabold font-outfit text-white mb-1">
        {value.toString().padStart(2, '0')}
      </span>
      <span className="text-[10px] md:text-xs uppercase tracking-widest text-blue-400 font-bold">
        {label}
      </span>
    </div>
  );

  return (
    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 w-full max-w-4xl mx-auto">
      <Unit value={timeLeft.days} label="Days" />
      <Unit value={timeLeft.hours} label="Hours" />
      <Unit value={timeLeft.minutes} label="Minutes" />
      <Unit value={timeLeft.seconds} label="Seconds" />
    </div>
  );
};

export default CountdownCard;

import React, { useState, useEffect } from 'react';
import { Subject } from '../types';
import { INITIAL_SUBJECTS } from '../constants';

const SubjectTracker: React.FC = () => {
  const [subjects, setSubjects] = useState<Subject[]>(() => {
    const saved = localStorage.getItem('al_2026_subjects');
    return saved ? JSON.parse(saved) : INITIAL_SUBJECTS;
  });

  useEffect(() => {
    localStorage.setItem('al_2026_subjects', JSON.stringify(subjects));
  }, [subjects]);

  const updateProgress = (id: string, delta: number) => {
    setSubjects(prev => prev.map(s => {
      if (s.id === id) {
        return { ...s, progress: Math.min(100, Math.max(0, s.progress + delta)) };
      }
      return s;
    }));
  };

  return (
    <div className="glass-card rounded-3xl p-6 md:p-8 w-full">
      <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
        <span className="text-2xl">📈</span> Syllabus Mastery
      </h3>
      <div className="space-y-6">
        {subjects.map(subject => (
          <div key={subject.id} className="group">
            <div className="flex justify-between items-center mb-2">
              <span className="text-sm font-medium text-slate-300">{subject.name}</span>
              <div className="flex items-center gap-3">
                <button 
                  onClick={() => updateProgress(subject.id, -5)}
                  className="w-8 h-8 rounded-full border border-slate-700 flex items-center justify-center hover:bg-slate-800 transition-colors"
                >
                  -
                </button>
                <span className="text-xs font-bold w-10 text-center">{subject.progress}%</span>
                <button 
                  onClick={() => updateProgress(subject.id, 5)}
                  className="w-8 h-8 rounded-full border border-slate-700 flex items-center justify-center hover:bg-slate-800 transition-colors"
                >
                  +
                </button>
              </div>
            </div>
            <div className="w-full bg-slate-900 rounded-full h-2 overflow-hidden border border-slate-800">
              <div 
                className={`h-full ${subject.color} transition-all duration-500 ease-out`}
                style={{ width: `${subject.progress}%` }}
              />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default SubjectTracker;

import React, { useState, useEffect, useCallback } from 'react';
import { EXAM_DATE, CATEGORY_ICONS } from './constants';
import { TimeLeft, GeminiAdvice } from './types';
import CountdownCard from './components/CountdownCard';
import SubjectTracker from './components/SubjectTracker';
import { getDailyAdvice } from './services/geminiService';

const App: React.FC = () => {
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [advice, setAdvice] = useState<GeminiAdvice | null>(null);
  const [isLoadingAdvice, setIsLoadingAdvice] = useState(false);

  const calculateTimeLeft = useCallback(() => {
    const difference = +EXAM_DATE - +new Date();

    if (difference > 0) {
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      });
    }
  }, []);

  useEffect(() => {
    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(timer);
  }, [calculateTimeLeft]);

  const fetchAdvice = async () => {
    setIsLoadingAdvice(true);
    const result = await getDailyAdvice(timeLeft.days);
    setAdvice(result);
    setIsLoadingAdvice(false);
  };

  useEffect(() => {
    // Fetch initial advice once timeLeft is calculated
    if (timeLeft.days > 0 && !advice) {
      fetchAdvice();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [timeLeft.days]);

  return (
    <div className="min-h-screen pb-20 selection:bg-blue-500/30">
      {/* Decorative Background Elements */}
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden -z-10">
        <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-600/10 blur-[120px] rounded-full" />
        <div className="absolute bottom-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full" />
      </div>

      <nav className="p-6 md:p-8 flex justify-between items-center max-w-7xl mx-auto">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-lg shadow-blue-600/20">A</div>
          <span className="text-xl font-bold tracking-tight font-outfit">LEVEL 2026</span>
        </div>
        <div className="flex items-center gap-4 text-xs font-medium text-slate-400 uppercase tracking-widest">
          <span className="hidden md:inline">Tentative Date: Nov 23, 2026</span>
          <div className="h-4 w-[1px] bg-slate-800 hidden md:block" />
          <span className="text-blue-400">Sri Lanka</span>
        </div>
      </nav>

      <main className="px-6 max-w-7xl mx-auto">
        {/* Hero Section */}
        <section className="mt-12 md:mt-20 text-center">
          <h1 className="text-4xl md:text-7xl font-extrabold font-outfit mb-6 tracking-tight leading-tight">
            The Journey to <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-emerald-400">Excellence</span> Starts Now.
          </h1>
          <p className="text-slate-400 text-lg md:text-xl max-w-2xl mx-auto mb-12">
            Every second counts. Prepare yourself for the most defining exam of your secondary education.
          </p>

          <div className="animate-glow rounded-3xl overflow-hidden mb-16">
            <CountdownCard timeLeft={timeLeft} />
          </div>
        </section>

        {/* Dynamic Content Section */}
        <section className="grid md:grid-cols-3 gap-8">
          <div className="md:col-span-2 space-y-8">
            {/* Gemini Advice Card */}
            <div className="glass-card rounded-3xl p-8 relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-110 transition-transform duration-500">
                <span className="text-9xl">✨</span>
              </div>

              <div className="relative z-10">
                <div className="flex items-center gap-3 mb-6">
                  <span className="bg-blue-600/20 text-blue-400 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest flex items-center gap-2">
                    <span className="animate-pulse w-2 h-2 bg-blue-400 rounded-full" />
                    Powered by Gemini
                  </span>
                  {advice && (
                    <span className="text-sm font-medium text-slate-400 italic">
                      {CATEGORY_ICONS[advice.category]} {advice.category.replace('-', ' ')}
                    </span>
                  )}
                </div>

                {isLoadingAdvice ? (
                  <div className="space-y-4 animate-pulse">
                    <div className="h-8 bg-slate-800 rounded w-1/3" />
                    <div className="h-20 bg-slate-800 rounded w-full" />
                  </div>
                ) : (
                  <>
                    <h2 className="text-2xl md:text-3xl font-bold mb-4 font-outfit">
                      {advice?.title || "Fetching your daily boost..."}
                    </h2>
                    <p className="text-slate-300 text-lg leading-relaxed mb-8">
                      {advice?.content}
                    </p>
                    <button 
                      onClick={fetchAdvice}
                      className="px-6 py-3 bg-white text-slate-900 font-bold rounded-2xl hover:bg-blue-50 transition-colors shadow-xl"
                    >
                      New Insight
                    </button>
                  </>
                )}
              </div>
            </div>

            {/* Quick Actions/Info */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="glass-card p-6 rounded-3xl border-l-4 border-blue-500">
                <h4 className="font-bold mb-2 flex items-center gap-2">
                  <span>📅</span> Upcoming Milestones
                </h4>
                <ul className="text-sm text-slate-400 space-y-2">
                  <li>• Application Deadlines (Est. mid-2026)</li>
                  <li>• Practical Exams (TBC)</li>
                  <li>• Admission Card Releases</li>
                </ul>
              </div>
              <div className="glass-card p-6 rounded-3xl border-l-4 border-emerald-500">
                <h4 className="font-bold mb-2 flex items-center gap-2">
                  <span>💡</span> Efficiency Tip
                </h4>
                <p className="text-sm text-slate-400">
                  Focus on Active Recall and Spaced Repetition. A/L is as much about strategy as it is about hard work.
                </p>
              </div>
            </div>
          </div>

          <aside className="space-y-8">
            <SubjectTracker />

            <div className="glass-card rounded-3xl p-6 text-center">
              <div className="text-4xl mb-3">🎯</div>
              <h4 className="font-bold mb-1">Stay Focused</h4>
              <p className="text-xs text-slate-500 mb-4">
                Avoid distractions and maintain a consistent sleep schedule.
              </p>
              <div className="flex justify-center gap-2">
                <div className="w-2 h-2 rounded-full bg-slate-800" />
                <div className="w-2 h-2 rounded-full bg-blue-500" />
                <div className="w-2 h-2 rounded-full bg-slate-800" />
              </div>
            </div>
          </aside>
        </section>
      </main>

      <footer className="mt-20 py-10 border-t border-slate-900 text-center text-slate-500 text-sm">
        <p>&copy; 2024 - 2026 AL Success Hub • Aiming for 3As</p>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { GeminiAdvice } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getDailyAdvice = async (daysRemaining: number): Promise<GeminiAdvice> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `The student has ${daysRemaining} days remaining for their GCE Advanced Level (A/L) 2026 examination in Sri Lanka. Provide a short, highly motivating, and practical piece of advice.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            category: { 
              type: Type.STRING,
              enum: ['motivation', 'study-tip', 'exam-strategy']
            }
          },
          required: ["title", "content", "category"]
        }
      },
    });

    return JSON.parse(response.text.trim()) as GeminiAdvice;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      title: "Keep Pushing Forward!",
