export interface ExamNews {
  text: string;
  sources: { uri: string; title: string }[];
}

export const fetchLatestExamNews = async (): Promise<ExamNews> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "What are the latest official or tentative dates for the GCE A/L 2026 examination in Sri Lanka? Check the Department of Examinations (doenets.lk) and official government news.",
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        uri: chunk.web?.uri,
        title: chunk.web?.title
      }))
      .filter((s: any) => s.uri && s.title) || [];

    return {
      text: response.text || "No specific updates found from official sources yet. Continue following the tentative schedule.",
      sources: sources.slice(0, 3) // Return top 3 sources
    };
  } catch (error) {
    console.error("Failed to fetch exam news:", error);
    return {
      text: "Unable to reach official servers. Please check doenets.lk directly.",
      sources: [{ uri: "https://www.doenets.lk", title: "Department of Examinations Sri Lanka" }]
    };
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { EXAM_DATE, CATEGORY_ICONS } from './constants';
import { TimeLeft, GeminiAdvice } from './types';
import CountdownCard from './components/CountdownCard';
import SubjectTracker from './components/SubjectTracker';
import { getDailyAdvice, fetchLatestExamNews, ExamNews } from './services/geminiService';

const App: React.FC = () => {
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [advice, setAdvice] = useState<GeminiAdvice | null>(null);
  const [news, setNews] = useState<ExamNews | null>(null);
  const [isLoadingAdvice, setIsLoadingAdvice] = useState(false);
  const [isLoadingNews, setIsLoadingNews] = useState(false);

  const calculateTimeLeft = useCallback(() => {
    const difference = +EXAM_DATE - +new Date();

    if (difference > 0) {
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      });
    }
  }, []);

  useEffect(() => {
    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(timer);
  }, [calculateTimeLeft]);

  const loadData = async () => {
    setIsLoadingAdvice(true);
    setIsLoadingNews(true);

    try {
      const [adviceResult, newsResult] = await Promise.all([
        getDailyAdvice(timeLeft.days),
        fetchLatestExamNews()
      ]);
      setAdvice(adviceResult);
      setNews(newsResult);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingAdvice(false);
      setIsLoadingNews(false);
    }
  };

  useEffect(() => {
    if (timeLeft.days > 0 && !advice) {
      loadData();
    }
  }, [timeLeft.days]);

  return (
    <div className="min-h-screen pb-20 selection:bg-blue-500/30">
      {/* Decorative Background Elements */}
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden -z-10">
        <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-600/10 blur-[120px] rounded-full" />
        <div className="absolute bottom-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full" />
      </div>

      <nav className="p-6 md:p-8 flex justify-between items-center max-w-7xl mx-auto">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-lg shadow-blue-600/20">A</div>
          <span className="text-xl font-bold tracking-tight font-outfit uppercase">A/L 2026 Hub</span>
        </div>
        <div className="flex items-center gap-4 text-xs font-medium text-slate-400 uppercase tracking-widest">
          <span className="hidden md:inline">Tentative: Nov 2026</span>
          <div className="h-4 w-[1px] bg-slate-800 hidden md:block" />
          <a href="https://www.doenets.lk" target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:underline">Official Site</a>
        </div>
      </nav>

      <main className="px-6 max-w-7xl mx-auto">
        {/* Hero Section */}
        <section className="mt-8 md:mt-12 text-center">
          <h1 className="text-4xl md:text-7xl font-extrabold font-outfit mb-6 tracking-tight leading-tight">
            Counting Down to <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-indigo-400">Success</span>.
          </h1>

          <div className="animate-glow rounded-3xl overflow-hidden mb-12">
            <CountdownCard timeLeft={timeLeft} />
          </div>
        </section>

        {/* Dynamic Content Grid */}
        <section className="grid md:grid-cols-12 gap-8">
          {/* Main Feed */}
          <div className="md:col-span-8 space-y-8">

            {/* Live Exam News Section (Grounding) */}
            <div className="glass-card rounded-3xl p-6 border border-blue-500/20 relative overflow-hidden bg-blue-500/5">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-bold flex items-center gap-2">
                  <span className="relative flex h-3 w-3">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500"></span>
                  </span>
                  Official Gov Updates
                </h3>
                <button 
                  onClick={loadData}
                  className="text-xs text-blue-400 hover:text-blue-300 font-medium"
                >
                  Refresh Feed
                </button>
              </div>

              {isLoadingNews ? (
                <div className="space-y-3 animate-pulse">
                  <div className="h-4 bg-slate-800 rounded w-full" />
                  <div className="h-4 bg-slate-800 rounded w-5/6" />
                </div>
              ) : (
                <div className="space-y-4">
                  <p className="text-slate-300 text-sm leading-relaxed">
                    {news?.text || "Checking government portals for 2026 scheduling updates..."}
                  </p>

                  {news?.sources && news.sources.length > 0 && (
                    <div className="pt-4 border-t border-slate-800">
                      <p className="text-[10px] uppercase tracking-wider text-slate-500 mb-2 font-bold">Verified Sources</p>
                      <div className="flex flex-wrap gap-2">
                        {news.sources.map((source, i) => (
                          <a 
                            key={i}
                            href={source.uri} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="text-xs bg-slate-800/50 hover:bg-slate-800 px-3 py-1.5 rounded-lg border border-slate-700 text-blue-300 transition-colors flex items-center gap-1"
                          >
                            <span>🔗</span> {source.title}
                          </a>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* Gemini Advice Card */}
            <div className="glass-card rounded-3xl p-8 group">
              <div className="relative z-10">
                <div className="flex items-center gap-3 mb-6">
                  <span className="bg-indigo-600/20 text-indigo-400 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest">
                    Study Strategy
                  </span>
                </div>

                {isLoadingAdvice ? (
                  <div className="space-y-4 animate-pulse">
                    <div className="h-8 bg-slate-800 rounded w-1/3" />
                    <div className="h-20 bg-slate-800 rounded w-full" />
                  </div>
                ) : (
                  <>
                    <h2 className="text-2xl md:text-3xl font-bold mb-4 font-outfit">
                      {advice?.title || "Preparing your plan..."}
                    </h2>
                    <p className="text-slate-300 text-lg leading-relaxed mb-6">
                      {advice?.content}
                    </p>
                  </>
                )}
              </div>
            </div>
          </div>

          {/* Sidebar */}
          <div className="md:col-span-4 space-y-8">
            <SubjectTracker />

            <div className="glass-card rounded-3xl p-6 border border-emerald-500/10">
              <h4 className="font-bold mb-4 flex items-center gap-2">
                <span className="text-emerald-400">⚡</span> Quick Check
              </h4>
              <div className="space-y-3">
                <div className="flex justify-between text-xs text-slate-400">
                  <span>Syllabus Covered</span>
                  <span className="text-emerald-400 font-bold">Avg. 12%</span>
                </div>
                <div className="w-full bg-slate-900 rounded-full h-1.5">
                  <div className="bg-emerald-500 h-full rounded-full w-[12%]" />
                </div>
                <p className="text-[10px] text-slate-500 italic mt-2">
                  *Based on your manual subject tracking. Update your mastery in the panel above.
                </p>
              </div>
            </div>
          </div>
        </section>
      </main>

      <footer className="mt-20 py-10 border-t border-slate-900/50 text-center text-slate-600 text-xs">
        <p>Information fetched from Department of Examinations (DoE) & official gazettes.</p>
        <p className="mt-2">&copy; 2026 A/L Success Hub • Sri Lanka Education Companion</p>
      </footer>
    </div>
  );
};

