}

import React, { useState, useEffect } from 'react';
import { Goal } from '../types';

const StudyGoals: React.FC = () => {
  const [goals, setGoals] = useState<Goal[]>(() => {
    const saved = localStorage.getItem('al_2026_goals');
    return saved ? JSON.parse(saved) : [];
  });
  const [inputValue, setInputValue] = useState('');

  useEffect(() => {
    localStorage.setItem('al_2026_goals', JSON.stringify(goals));
  }, [goals]);

  const addGoal = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;

    const newGoal: Goal = {
      id: crypto.randomUUID(),
      text: inputValue.trim(),
      completed: false,
      createdAt: Date.now(),
    };

    setGoals([newGoal, ...goals]);
    setInputValue('');
  };

  const toggleGoal = (id: string) => {
    setGoals(prev => prev.map(g => 
      g.id === id ? { ...g, completed: !g.completed } : g
    ));
  };

  const deleteGoal = (id: string) => {
    setGoals(prev => prev.filter(g => g.id !== id));
  };

  const completedCount = goals.filter(g => g.completed).length;

  return (
    <div className="glass-card rounded-3xl p-6 md:p-8 w-full mt-8">
      <div className="flex justify-between items-center mb-6">
        <h3 className="text-xl font-bold flex items-center gap-2">
          <span className="text-2xl">🎯</span> Study Goals
        </h3>
        {goals.length > 0 && (
          <span className="text-xs font-bold text-blue-400 bg-blue-500/10 px-2 py-1 rounded-full">
            {completedCount}/{goals.length}
          </span>
        )}
      </div>

      <form onSubmit={addGoal} className="mb-6 flex gap-2">
        <input
          type="text"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          placeholder="New study goal..."
          className="flex-1 bg-slate-900/50 border border-slate-700 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-blue-500 transition-colors"
        />
        <button
          type="submit"
          className="bg-blue-600 hover:bg-blue-500 text-white p-2 rounded-xl transition-colors"
          aria-label="Add goal"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" />
          </svg>
        </button>
      </form>

      <div className="space-y-3 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
        {goals.length === 0 ? (
          <p className="text-center text-slate-500 text-sm py-4">No goals set yet. Start small!</p>
        ) : (
          goals.map(goal => (
            <div 
              key={goal.id} 
              className={`flex items-center gap-3 p-3 rounded-xl border border-transparent transition-all group ${
                goal.completed ? 'bg-slate-900/30' : 'bg-slate-800/30 border-slate-700/30 hover:border-slate-600'
              }`}
            >
              <button
                onClick={() => toggleGoal(goal.id)}
                className={`w-5 h-5 rounded-md border flex items-center justify-center transition-colors ${
                  goal.completed ? 'bg-blue-500 border-blue-500' : 'border-slate-600 hover:border-blue-400'
                }`}
              >
                {goal.completed && (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5 text-white" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                  </svg>
                )}
              </button>
              <span className={`text-sm flex-1 transition-all ${
                goal.completed ? 'text-slate-500 line-through' : 'text-slate-200'
              }`}>
                {goal.text}
              </span>
              <button
                onClick={() => deleteGoal(goal.id)}
                className="opacity-0 group-hover:opacity-100 text-slate-600 hover:text-red-400 transition-all"
                aria-label="Delete goal"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
                </svg>
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

