import { GoogleGenAI, Type } from "@google/genai";
import { GeminiAdvice } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getDailyAdvice = async (daysRemaining: number): Promise<GeminiAdvice> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `The student has ${daysRemaining} days remaining for their GCE Advanced Level (A/L) 2026 examination in Sri Lanka. Provide a short, highly motivating, and practical piece of advice.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            category: { 
              type: Type.STRING,
              enum: ['motivation', 'study-tip', 'exam-strategy']
            }
          },
          required: ["title", "content", "category"]
        }
      },
    });

    return JSON.parse(response.text.trim()) as GeminiAdvice;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      title: "Keep Pushing Forward!",
      content: "Consistency is the key to mastering A/L. Small daily steps lead to massive success in 2026.",
      category: "motivation"
    };
  }
};

export interface ExamNews {
  text: string;
  sources: { uri: string; title: string }[];
  verifiedDate?: string; // ISO string if found
  isConfirmed: boolean;
}

export const fetchLatestExamNews = async (): Promise<ExamNews> => {
  try {
    // We use a high-precision prompt to extract the exact date if possible
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview", // Use Pro for better extraction of specific dates
      contents: "Search for the MOST RECENT official announcement regarding GCE A/L 2026 dates from the Department of Examinations Sri Lanka (doenets.lk). If a specific date is mentioned (even tentative), provide it. If no specific date exists yet, identify the month/window (e.g., Nov 2026). Check official gazettes and government news portals.",
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        uri: chunk.web?.uri,
        title: chunk.web?.title
      }))
      .filter((s: any) => s.uri && s.title) || [];

    // Simple heuristic to check for 'confirmed' vs 'tentative' in the text
    const text = response.text || "";
    const isConfirmed = text.toLowerCase().includes("confirmed") || text.toLowerCase().includes("official date is");

    return {
      text: text || "Scanning official government portals for 2026 schedules...",
      sources: sources.slice(0, 4),
      isConfirmed
    };
  } catch (error) {
    console.error("Failed to fetch exam news:", error);
    return {
      text: "Unable to reach official servers. Please check doenets.lk directly for 100% verification.",
      sources: [{ uri: "https://www.doenets.lk", title: "Department of Examinations Sri Lanka" }],
      isConfirmed: false
    };
  }
};

