import { GoogleGenAI, Type } from "@google/genai";
import { GeminiAdvice } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getDailyAdvice = async (daysRemaining: number): Promise<GeminiAdvice> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `The student has ${daysRemaining} days remaining for their GCE Advanced Level (A/L) 2026 examination in Sri Lanka. Provide a short, highly motivating, and practical piece of advice tailored to a student who still has significant time but needs to build a strong foundation.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            category: { 
              type: Type.STRING,
              enum: ['motivation', 'study-tip', 'exam-strategy']
            }
          },
          required: ["title", "content", "category"]
        }
      },
    });

    return JSON.parse(response.text.trim()) as GeminiAdvice;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      title: "Keep Pushing Forward!",
      content: "Consistency is the key to mastering A/L. Small daily steps lead to massive success in 2026.",
      category: "motivation"
    };
  }
};

export interface ExamNews {
  text: string;
  sources: { uri: string; title: string }[];
  verifiedDate?: string; 
  isConfirmed: boolean;
}

export const fetchLatestExamNews = async (): Promise<ExamNews> => {
  try {
    // Highly specific prompt to avoid 2025 news overlap
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: "Search for the GCE A/L 2026 (2026 Academic Batch) official examination schedule from the Department of Examinations Sri Lanka (doenets.lk). IGNORE any news regarding the 2024 or 2025 exams. We specifically need the tentative or confirmed start date for the year 2026. If the exact day isn't released, find the officially projected month for 2026.",
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        uri: chunk.web?.uri,
        title: chunk.web?.title
      }))
      .filter((s: any) => s.uri && s.title) || [];

    const text = response.text || "";
    // Only mark as confirmed if the text explicitly references the year 2026 and 'official' status
    const isConfirmed = text.includes("2026") && (text.toLowerCase().includes("confirmed") || text.toLowerCase().includes("officially announced"));

    return {
      text: text || "Scanning official government portals strictly for the 2026 A/L schedule...",
      sources: sources.slice(0, 4),
      isConfirmed
    };
  } catch (error) {
    console.error("Failed to fetch exam news:", error);
    return {
      text: "Unable to reach official servers. Please check doenets.lk directly for 100% 2026 verification.",
      sources: [{ uri: "https://www.doenets.lk", title: "Department of Examinations Sri Lanka" }],
      isConfirmed: false
    };
  }
};

