        if (!isNaN(foundDate.getTime()) && foundDate.getFullYear() === 2026 && foundDate.getTime() > Date.now()) {
          setCurrentExamDate(foundDate);
        }
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingNews(false);
    }
  };

