    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingAdvice(false);
    }
    refreshNews();
  };

  useEffect(() => {
    if (timeLeft.days > 0 && !advice) {
      loadData();
    }
  }, [timeLeft.days]);

  return (
