          <div className="w-12 h-12 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl flex items-center justify-center font-black text-2xl shadow-xl shadow-blue-900/40 text-white transform rotate-3">A</div>
          <div className="flex flex-col">
            <span className="text-xl font-black tracking-tighter font-outfit uppercase leading-none">A/L 2026</span>
            <span className="text-[10px] text-blue-400 font-bold tracking-widest uppercase text-left">Academic Hub</span>
          </div>
        </div>
        <div className="flex items-center gap-6 text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em]">
