import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { EXAM_DATE, INITIAL_SUBJECTS } from './constants';
import { TimeLeft, GeminiAdvice, Subject, User } from './types';
import CountdownCard from './components/CountdownCard';
import SubjectTracker from './components/SubjectTracker';
import StudyGoals from './components/StudyGoals';
import ExamNews from './components/ExamNews';
import LoginPage from './components/LoginPage';
import { getDailyAdvice, fetchLatestExamNews, ExamNews as ExamNewsType } from './services/geminiService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentExamDate, setCurrentExamDate] = useState<Date>(EXAM_DATE);
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [advice, setAdvice] = useState<GeminiAdvice | null>(null);
  const [news, setNews] = useState<ExamNewsType | null>(null);
  const [lastNewsUpdate, setLastNewsUpdate] = useState<string | null>(null);
  const [isLoadingAdvice, setIsLoadingAdvice] = useState(false);
  const [isLoadingNews, setIsLoadingNews] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(true);

  // Lifted state for subjects to sync with Batch Index
  const [subjects, setSubjects] = useState<Subject[]>(() => {
    const saved = localStorage.getItem('al_2026_subjects');
    return saved ? JSON.parse(saved) : INITIAL_SUBJECTS;
  });

  // Calculate overall mastery (Batch Index)
  const batchIndex = useMemo(() => {
    if (subjects.length === 0) return 0;
    const total = subjects.reduce((acc, s) => acc + s.progress, 0);
    return Math.round(total / subjects.length);
  }, [subjects]);

  // Check for existing session
  useEffect(() => {
    const savedUser = localStorage.getItem('al_2026_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
    setIsAuthLoading(false);
  }, []);

  // Save subjects to localStorage
  useEffect(() => {
    localStorage.setItem('al_2026_subjects', JSON.stringify(subjects));
  }, [subjects]);

  const handleLogin = (name: string, remember: boolean) => {
    const newUser = { name, isLoggedIn: true };
    setUser(newUser);
    if (remember) {
      localStorage.setItem('al_2026_user', JSON.stringify(newUser));
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('al_2026_user');
  };

  const updateSubjectProgress = (id: string, delta: number) => {
    setSubjects(prev => prev.map(s => {
      if (s.id === id) {
        return { ...s, progress: Math.min(100, Math.max(0, s.progress + delta)) };
      }
      return s;
    }));
  };

  const calculateTimeLeft = useCallback(() => {
    const now = new Date();
    const difference = currentExamDate.getTime() - now.getTime();

    if (difference > 0) {
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      });
    } else {
      setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
    }
  }, [currentExamDate]);

  useEffect(() => {
    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(timer);
  }, [calculateTimeLeft]);

  const refreshNews = async () => {
    setIsLoadingNews(true);
    try {
      const newsResult = await fetchLatestExamNews();
      setNews(newsResult);
      setLastNewsUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));

      const dateMatch = newsResult.text.match(/2026-\d{2}-\d{2}/);
      if (dateMatch) {
        const foundDate = new Date(dateMatch[0]);
        if (!isNaN(foundDate.getTime()) && foundDate.getFullYear() === 2026 && foundDate.getTime() > Date.now()) {
          setCurrentExamDate(foundDate);
        }
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingNews(false);
    }
  };

  const loadData = async () => {
    setIsLoadingAdvice(true);
    try {
      const adviceResult = await getDailyAdvice(timeLeft.days);
      setAdvice(adviceResult);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingAdvice(false);
    }
    refreshNews();
  };

  useEffect(() => {
    if (user && timeLeft.days > 0 && !advice) {
      loadData();
    }
  }, [user, timeLeft.days]);

  if (isAuthLoading) {
    return <div className="min-h-screen bg-slate-950 flex items-center justify-center">
      <div className="w-12 h-12 rounded-2xl border-4 border-blue-500/20 border-t-blue-500 animate-spin" />
    </div>;
  }

  if (!user) {
    return <LoginPage onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen pb-20 selection:bg-blue-500/30">
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden -z-10">
        <div className="absolute top-[-20%] right-[-10%] w-[60%] h-[60%] bg-blue-600/10 blur-[140px] rounded-full animate-float" />
        <div className="absolute bottom-[-10%] left-[-10%] w-[50%] h-[50%] bg-indigo-600/10 blur-[140px] rounded-full animate-float" style={{ animationDelay: '2s' }} />
      </div>

      <nav className="p-6 md:p-8 flex justify-between items-center max-w-7xl mx-auto animate-reveal">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl flex items-center justify-center font-black text-2xl shadow-xl shadow-blue-900/40 text-white transform rotate-3 transition-transform hover:rotate-0 duration-500">A</div>
          <div className="flex flex-col">
            <div className="flex items-center gap-2">
              <span className="text-xl font-black tracking-tighter font-outfit uppercase leading-none">A/L 2026</span>
              <span className="w-1 h-1 rounded-full bg-slate-700" />
              <span className="text-xs font-bold text-slate-400 capitalize">{user.name}</span>
            </div>
            <span className="text-[10px] text-blue-400 font-bold tracking-widest uppercase text-left">Developed by Pramod Mihiranga</span>
          </div>
        </div>
        <div className="flex items-center gap-6 text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em]">
          <button 
            onClick={handleLogout}
            className="hover:text-red-400 transition-colors hidden md:block"
          >
            Switch User
          </button>
          <div className="hidden lg:flex items-center gap-2">
            <span className={`w-2.5 h-2.5 rounded-full transition-colors duration-500 ${news?.isConfirmed ? 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]' : 'bg-amber-500 animate-pulse'}`} />
            {news?.isConfirmed ? 'Verified 2026 Accuracy' : 'Scanning 2026 Portals'}
          </div>
          <a href="https://www.doenets.lk" target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:text-blue-300 transition-all border-b border-blue-400/20 pb-0.5">Official Site</a>
        </div>
      </nav>

      <main className="px-6 max-w-7xl mx-auto">
        <section className="mt-12 md:mt-20 text-center mb-16 md:mb-24 animate-reveal delay-100">
          <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-slate-900/50 border border-white/5 text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] mb-8 transition-colors hover:bg-slate-900/80">
            <span className="w-1.5 h-1.5 rounded-full bg-blue-500" />
            Active Session: {user.name}
          </div>
          <h1 className="text-5xl md:text-8xl font-black font-outfit mb-8 tracking-tighter leading-[0.9] text-white">
            Future is <br className="hidden md:block" />
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-indigo-400 to-cyan-400">Locked In.</span>
          </h1>

          <div className="relative pt-8 animate-reveal delay-200">
            <div className="relative z-10">
              <CountdownCard timeLeft={timeLeft} />
            </div>
            <div className="mt-8 flex justify-center">
              <div className="glass-card px-4 py-2 rounded-2xl flex items-center gap-3 border-white/10">
                <span className="text-xs text-slate-500 font-bold uppercase tracking-widest">Exam Year:</span>
                <span className="text-sm text-blue-400 font-mono-tech font-bold">2026</span>
                <div className="w-[1px] h-3 bg-slate-800" />
                <span className="text-xs text-slate-500 font-bold uppercase tracking-widest">Date:</span>
                <span className="text-sm text-white font-mono-tech font-bold">
                  {currentExamDate.toLocaleDateString('en-GB', { day: '2-digit', month: 'short' })}
                </span>
                <div className="w-[1px] h-3 bg-slate-800" />
