import { GoogleGenAI, Type } from "@google/genai";
import { GeminiAdvice, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getDailyAdvice = async (daysRemaining: number): Promise<GeminiAdvice> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `The student has ${daysRemaining} days remaining for their GCE Advanced Level (A/L) 2026 examination in Sri Lanka. Provide a short, highly motivating, and practical piece of advice tailored to a student who still has significant time but needs to build a strong foundation.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            category: { 
              type: Type.STRING,
              enum: ['motivation', 'study-tip', 'exam-strategy']
            }
          },
          required: ["title", "content", "category"]
        }
      },
    });

    return JSON.parse(response.text.trim()) as GeminiAdvice;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      title: "Keep Pushing Forward!",
      content: "Consistency is the key to mastering A/L. Small daily steps lead to massive success in 2026.",
      category: "motivation"
    };
  }
};

export const chatWithStudyBuddy = async (history: ChatMessage[], prompt: string): Promise<string> => {
  try {
    const chat = ai.chats.create({
      model: "gemini-3-flash-preview",
      config: {
        systemInstruction: "You are 'A-Level Buddy', a supportive AI tutor for Sri Lankan GCE A/L students (2026 Batch). Help them with study plans, subject explanations, and motivation. Keep responses concise and formatted for a small chat window. Use Sri Lankan context where appropriate.",
      }
    });

    // We send just the latest message for simplicity in this implementation
    const result = await chat.sendMessage({ message: prompt });
    return result.text || "I'm processing that. One moment...";
  } catch (error) {
    console.error("Chat Error:", error);
    return "Connection to the study brain interrupted. Try again in a bit!";
  }
};

export interface ExamNews {
  text: string;
  sources: { uri: string; title: string }[];
  verifiedDate?: string; 
  isConfirmed: boolean;
}

export const fetchLatestExamNews = async (): Promise<ExamNews> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: "Search for the GCE A/L 2026 official examination schedule from the Department of Examinations Sri Lanka (doenets.lk). Focus strictly on the 2026 academic cycle.",
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        uri: chunk.web?.uri,
        title: chunk.web?.title
      }))
      .filter((s: any) => s.uri && s.title) || [];

    const text = response.text || "";
    const isConfirmed = text.includes("2026") && (text.toLowerCase().includes("confirmed") || text.toLowerCase().includes("officially announced"));

    return {
      text: text || "Scanning official government portals strictly for the 2026 A/L schedule...",
      sources: sources.slice(0, 4),
      isConfirmed
    };
  } catch (error) {
    console.error("Failed to fetch exam news:", error);
    return {
      text: "Unable to reach official servers. Please check doenets.lk directly.",
      sources: [{ uri: "https://www.doenets.lk", title: "Department of Examinations Sri Lanka" }],
      isConfirmed: false
    };
  }
};

import React, { useState, useEffect, useRef } from 'react';

const FocusTimer: React.FC = () => {
  const [timeLeft, setTimeLeft] = useState(25 * 60);
  const [isActive, setIsActive] = useState(false);
  const [mode, setMode] = useState<'work' | 'break'>('work');
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    if (isActive && timeLeft > 0) {
      timerRef.current = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      handleComplete();
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isActive, timeLeft]);

  const handleComplete = () => {
    setIsActive(false);
    // Notification logic could go here
    if (mode === 'work') {
      setMode('break');
      setTimeLeft(5 * 60);
    } else {
      setMode('work');
      setTimeLeft(25 * 60);
    }
  };

  const toggleTimer = () => setIsActive(!isActive);
  const resetTimer = () => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? 25 * 60 : 5 * 60);
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className="glass-card rounded-3xl p-6 border-cyan-500/20 bg-cyan-500/5">
      <div className="flex justify-between items-center mb-6">
        <h3 className="text-sm font-black uppercase tracking-widest text-cyan-400">Focus Hub</h3>
        <span className={`text-[10px] font-bold px-2 py-0.5 rounded ${mode === 'work' ? 'bg-orange-500/10 text-orange-400' : 'bg-emerald-500/10 text-emerald-400'}`}>
          {mode === 'work' ? 'Deep Work' : 'Refuel Break'}
        </span>
      </div>

      <div className="text-center py-4">
        <div className="text-6xl font-black font-mono-tech text-white mb-6 tracking-tighter">
          {formatTime(timeLeft)}
        </div>

        <div className="flex gap-3 justify-center">
          <button 
            onClick={toggleTimer}
            className={`px-8 py-3 rounded-2xl font-black uppercase tracking-widest text-[10px] transition-all ${
              isActive ? 'bg-slate-800 text-slate-400 hover:bg-slate-700' : 'bg-cyan-600 text-white shadow-lg shadow-cyan-900/40 hover:bg-cyan-500'
            }`}
          >
            {isActive ? 'Pause' : 'Start'}
          </button>
          <button 
            onClick={resetTimer}
            className="w-12 h-12 flex items-center justify-center rounded-2xl bg-slate-900 border border-slate-800 text-slate-500 hover:text-white transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 110 2H4a1 1 0 01-1-1V3a1 1 0 011-1z" clipRule="evenodd" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default FocusTimer;

import React, { useState, useEffect } from 'react';
import { Resource } from '../types';

const ResourceVault: React.FC = () => {
  const [resources, setResources] = useState<Resource[]>(() => {
    const saved = localStorage.getItem('al_2026_resources');
    return saved ? JSON.parse(saved) : [
      { id: '1', title: 'Department of Examinations', url: 'https://www.doenets.lk', category: 'Portal' },
      { id: '2', title: 'YouTube: AL Physics Lessons', url: 'https://youtube.com', category: 'YouTube' }
    ];
  });
  const [showAdd, setShowAdd] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newUrl, setNewUrl] = useState('');

  useEffect(() => {
    localStorage.setItem('al_2026_resources', JSON.stringify(resources));
  }, [resources]);

  const addResource = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTitle || !newUrl) return;
    const res: Resource = {
      id: crypto.randomUUID(),
      title: newTitle,
      url: newUrl.startsWith('http') ? newUrl : `https://${newUrl}`,
      category: 'Other'
    };
    setResources([...resources, res]);
    setNewTitle('');
    setNewUrl('');
    setShowAdd(false);
  };

  const deleteResource = (id: string) => {
    setResources(resources.filter(r => r.id !== id));
  };

  return (
    <div className="glass-card rounded-3xl p-6 md:p-8 w-full">
      <div className="flex justify-between items-center mb-6">
        <h3 className="text-xl font-bold flex items-center gap-2 text-white">
          <span className="text-2xl">📑</span> Resource Vault
        </h3>
        <button 
          onClick={() => setShowAdd(!showAdd)}
          className="text-[10px] font-black uppercase tracking-widest text-blue-400 border border-blue-500/20 px-3 py-1.5 rounded-xl hover:bg-blue-500/10 transition-all"
        >
          {showAdd ? 'Cancel' : 'Add Link'}
        </button>
      </div>

      {showAdd && (
        <form onSubmit={addResource} className="mb-6 space-y-3 bg-slate-900/50 p-4 rounded-2xl border border-white/5">
          <input
            type="text"
            placeholder="Title (e.g., Physics Unit 01)"
            value={newTitle}
            onChange={(e) => setNewTitle(e.target.value)}
            className="w-full bg-slate-800 border-none rounded-xl px-4 py-2 text-xs text-white focus:ring-1 focus:ring-blue-500"
          />
          <input
            type="text"
            placeholder="Link (URL)"
            value={newUrl}
            onChange={(e) => setNewUrl(e.target.value)}
            className="w-full bg-slate-800 border-none rounded-xl px-4 py-2 text-xs text-white focus:ring-1 focus:ring-blue-500"
          />
          <button type="submit" className="w-full bg-blue-600 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest text-white">Save Resource</button>
        </form>
      )}

      <div className="space-y-3">
        {resources.map(res => (
          <div key={res.id} className="flex items-center gap-3 p-3 rounded-2xl bg-slate-900/30 border border-white/5 hover:border-white/10 transition-all group">
            <div className="w-8 h-8 rounded-xl bg-slate-800 flex items-center justify-center text-xs">
              {res.category === 'YouTube' ? '📹' : '🔗'}
