import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithStudyBuddy } from '../services/geminiService';

const AIChatBuddy: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages([...messages, userMsg]);
    setInput('');
    setIsTyping(true);

    const response = await chatWithStudyBuddy(messages, input);
    const botMsg: ChatMessage = { role: 'model', text: response, timestamp: Date.now() };
    setMessages(prev => [...prev, botMsg]);
    setIsTyping(false);
  };

  return (
    <div className="glass-card rounded-[2.5rem] p-8 border-indigo-500/10 flex flex-col h-[500px]">
      <div className="flex items-center justify-between mb-6">
        <h3 className="font-black text-sm uppercase tracking-widest flex items-center gap-3 text-white">
          <span className="text-indigo-400">🤖</span> 2026 Study Buddy
        </h3>
        <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.5)]" />
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto pr-2 custom-scrollbar space-y-4 mb-6">
        {messages.length === 0 && (
          <div className="text-center py-10">
