            <div className="glass-card rounded-[2rem] p-8 border border-emerald-500/10 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 blur-3xl rounded-full translate-x-10 -translate-y-10" />
              <h4 className="font-black text-sm uppercase tracking-widest mb-6 text-emerald-400">📊 Batch Index</h4>
              <div className="space-y-5">
                <div className="flex justify-between items-end">
                  <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Syllabus Progress</span>
                  <span className="text-emerald-400 font-black text-2xl font-mono-tech leading-none">~{batchIndex}%</span>
                </div>
                <div className="w-full bg-slate-900 rounded-full h-3 p-1 border border-slate-800">
