import CountdownCard from './components/CountdownCard';
import SubjectTracker from './components/SubjectTracker';
import StudyGoals from './components/StudyGoals';
import ExamNews from './components/ExamNews';
import LoginPage from './components/LoginPage';
import FocusTimer from './components/FocusTimer';
import ResourceVault from './components/ResourceVault';
import AIChatBuddy from './components/AIChatBuddy';
import CurriculumHub from './components/CurriculumHub';
import { getDailyAdvice, fetchLatestExamNews, ExamNews as ExamNewsType } from './services/geminiService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentExamDate, setCurrentExamDate] = useState<Date>(EXAM_DATE);
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [news, setNews] = useState<ExamNewsType | null>(null);
  const [lastNewsUpdate, setLastNewsUpdate] = useState<string | null>(null);
  const [isLoadingNews, setIsLoadingNews] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(true);

  // Initialize subjects based on saved data or default to first stream
  const [subjects, setSubjects] = useState<Subject[]>([]);

  const batchIndex = useMemo(() => {
    if (subjects.length === 0) return 0;
    const total = subjects.reduce((acc, s) => acc + s.progress, 0);
    return Math.round(total / subjects.length);
  }, [subjects]);

  useEffect(() => {
    const savedUser = localStorage.getItem('al_2026_user');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);

      const savedSubjects = localStorage.getItem(`al_2026_subjects_${parsedUser.streamId}`);
      if (savedSubjects) {
        setSubjects(JSON.parse(savedSubjects));
      } else {
        const defaultStream = AL_STREAMS.find(s => s.id === parsedUser.streamId) || AL_STREAMS[0];
        setSubjects(defaultStream.subjects);
      }
    }
    setIsAuthLoading(false);
  }, []);

  useEffect(() => {
    if (user && subjects.length > 0) {
      localStorage.setItem(`al_2026_subjects_${user.streamId}`, JSON.stringify(subjects));
    }
  }, [subjects, user]);

  const handleLogin = (name: string, remember: boolean, streamId: string) => {
    const newUser = { name, isLoggedIn: true, streamId };
    setUser(newUser);
    if (remember) localStorage.setItem('al_2026_user', JSON.stringify(newUser));

    // Set initial subjects for the stream
    const stream = AL_STREAMS.find(s => s.id === streamId) || AL_STREAMS[0];
    setSubjects(stream.subjects);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('al_2026_user');
    setSubjects([]);
  };

  const toggleUnit = (subjectId: string, unitId: string) => {
    setSubjects(prev => prev.map(s => {
      if (s.id === subjectId) {
        const newUnits = s.units.map(u => 
          u.id === unitId ? { ...u, completed: !u.completed } : u
        );
        const completedCount = newUnits.filter(u => u.completed).length;
        const newProgress = Math.round((completedCount / newUnits.length) * 100);
        return { ...s, units: newUnits, progress: newProgress };
      }
      return s;
    }));
  };

  const calculateTimeLeft = useCallback(() => {
    const now = new Date();
    const difference = currentExamDate.getTime() - now.getTime();
    if (difference > 0) {
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      });
    } else {
      setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
    }
  }, [currentExamDate]);

  useEffect(() => {
    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(timer);
  }, [calculateTimeLeft]);

  const refreshNews = async () => {
    setIsLoadingNews(true);
    try {
      const newsResult = await fetchLatestExamNews();
      setNews(newsResult);
      setLastNewsUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingNews(false);
    }
  };

  useEffect(() => {
    if (user && timeLeft.days > 0) {
      refreshNews();
    }
  }, [user, timeLeft.days]);

  if (isAuthLoading) return <div className="min-h-screen bg-slate-950 flex items-center justify-center"><div className="w-12 h-12 rounded-2xl border-4 border-blue-500/20 border-t-blue-500 animate-spin" /></div>;
  if (!user) return <LoginPage onLogin={handleLogin} />;

  return (
    <div className="min-h-screen pb-20 selection:bg-blue-500/30">
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden -z-10">
        <div className="absolute top-[-20%] right-[-10%] w-[60%] h-[60%] bg-blue-600/10 blur-[140px] rounded-full animate-float" />
        <div className="absolute bottom-[-10%] left-[-10%] w-[50%] h-[50%] bg-indigo-600/10 blur-[140px] rounded-full animate-float" style={{ animationDelay: '2s' }} />
      </div>

      <nav className="p-6 md:p-8 flex justify-between items-center max-w-7xl mx-auto animate-reveal">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl flex items-center justify-center font-black text-2xl shadow-xl shadow-blue-900/40 text-white transform rotate-3 transition-transform hover:rotate-0 duration-500">A</div>
          <div className="flex flex-col">
            <div className="flex items-center gap-2">
              <span className="text-xl font-black tracking-tighter font-outfit uppercase leading-none">A/L 2026</span>
              <span className="w-1 h-1 rounded-full bg-slate-700" />
              <span className="text-xs font-bold text-slate-400 capitalize">{user.name}</span>
            </div>
            <span className="text-[10px] text-blue-400 font-bold tracking-widest uppercase text-left">Developed by Pramod Mihiranga</span>
          </div>
        </div>
        <div className="flex items-center gap-6 text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em]">
          <button onClick={handleLogout} className="hover:text-red-400 transition-colors hidden md:block">Switch User</button>
          <a href="https://www.doenets.lk" target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:text-blue-300 transition-all border-b border-blue-400/20 pb-0.5">Official Site</a>
        </div>
      </nav>

      <main className="px-6 max-w-7xl mx-auto">
        <section className="mt-12 md:mt-20 text-center mb-16 md:mb-24 animate-reveal delay-100">
          <h1 className="text-5xl md:text-8xl font-black font-outfit mb-8 tracking-tighter leading-[0.9] text-white">
            Targeting <br className="hidden md:block" />
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-indigo-400 to-cyan-400">Success.</span>
          </h1>
          <div className="relative pt-8 animate-reveal delay-200">
            <CountdownCard timeLeft={timeLeft} />
            <div className="mt-8 flex justify-center">
              <div className="glass-card px-4 py-2 rounded-2xl flex items-center gap-3 border-white/10">
                <span className="text-xs text-slate-500 font-bold uppercase tracking-widest">Exam Start:</span>
                <span className="text-sm text-white font-mono-tech font-bold">Aug 05, 2026</span>
              </div>
            </div>
          </div>
        </section>

        <section className="grid md:grid-cols-12 gap-8 lg:gap-10 items-start animate-reveal delay-300">
          {/* Main Content Area */}
          <div className="md:col-span-8 space-y-10">
            <CurriculumHub subjects={subjects} toggleUnit={toggleUnit} />

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <FocusTimer />
              <ExamNews news={news} isLoading={isLoadingNews} onRefresh={refreshNews} lastUpdated={lastNewsUpdate} />
            </div>

            <AIChatBuddy />

            <ResourceVault />
          </div>

          {/* Sidebar Area */}
          <div className="md:col-span-4 space-y-10">
            <div className="glass-card rounded-[2rem] p-8 border border-emerald-500/10 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 blur-3xl rounded-full translate-x-10 -translate-y-10" />
              <h4 className="font-black text-sm uppercase tracking-widest mb-6 text-emerald-400">📊 Batch Index</h4>
              <div className="space-y-5">
                <div className="flex justify-between items-end">
                  <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Syllabus Progress</span>
                  <span className="text-emerald-400 font-black text-2xl font-mono-tech leading-none">~{batchIndex}%</span>
                </div>
                <div className="w-full bg-slate-900 rounded-full h-3 p-1 border border-slate-800">
                  <div className="bg-gradient-to-r from-emerald-600 to-emerald-400 h-full rounded-full transition-all duration-1000 shadow-[0_0_10px_rgba(16,185,129,0.3)]" style={{ width: `${batchIndex}%` }} />
                </div>
                <p className="text-[10px] text-slate-500 font-medium italic">Complete lessons in the Curriculum Hub to boost your overall completion.</p>
              </div>
            </div>

            <SubjectTracker subjects={subjects} />
            <StudyGoals />
          </div>
        </section>
      </main>

      <footer className="mt-32 py-12 border-t border-white/5 text-center animate-reveal delay-400">
        <p className="text-slate-600 text-[10px] font-bold uppercase tracking-[0.4em]">Sri Lanka A/L 2026 Candidate Portal</p>
        <p className="text-blue-400 text-[11px] font-black uppercase tracking-[0.3em] mt-4">Designed & Developed by Pramod Mihiranga</p>
      </footer>
    </div>
  );
};

export default App;

