export default SubjectTracker;

import React, { useState } from 'react';
import { AL_STREAMS } from '../constants';

interface LoginPageProps {
  onLogin: (name: string, remember: boolean, streamId: string) => void;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin }) => {
  const [name, setName] = useState('');
  const [streamId, setStreamId] = useState(AL_STREAMS[0].id);
  const [remember, setRemember] = useState(true);
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) {
      setError('Please enter your name');
      return;
    }
    if (name.length < 2) {
      setError('Name is too short');
      return;
    }
    onLogin(name, remember, streamId);
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-6 relative overflow-hidden">
      <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-600/20 blur-[120px] rounded-full animate-float" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-600/20 blur-[120px] rounded-full animate-float" style={{ animationDelay: '3s' }} />

      <div className="glass-card w-full max-w-md p-10 rounded-[2.5rem] relative z-10 animate-reveal">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl flex items-center justify-center font-black text-4xl shadow-2xl shadow-blue-900/40 text-white mx-auto mb-6 transform rotate-6 hover:rotate-0 transition-transform duration-500">A</div>
          <h1 className="text-3xl font-black font-outfit text-white tracking-tighter">SUCCESS HUB</h1>
          <p className="text-slate-400 text-sm font-medium mt-2">GCE Advanced Level 2026 Batch</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2 ml-1">Candidate Name</label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Enter your name..."
              className="w-full bg-slate-900/50 border border-slate-700/50 rounded-2xl px-5 py-4 text-white placeholder-slate-600 focus:outline-none focus:border-blue-500 transition-all font-medium"
            />
          </div>

          <div>
            <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2 ml-1">Academic Stream</label>
            <select
              value={streamId}
              onChange={(e) => setStreamId(e.target.value)}
              className="w-full bg-slate-900/50 border border-slate-700/50 rounded-2xl px-5 py-4 text-white appearance-none focus:outline-none focus:border-blue-500 transition-all font-medium cursor-pointer"
            >
              {AL_STREAMS.map(stream => (
                <option key={stream.id} value={stream.id} className="bg-slate-950">{stream.name}</option>
              ))}
            </select>
          </div>

          <div className="flex items-center justify-between px-1">
            <label className="flex items-center gap-3 cursor-pointer group">
              <div className="relative">
                <input
                  type="checkbox"
                  checked={remember}
                  onChange={(e) => setRemember(e.target.checked)}
                  className="sr-only peer"
                />
                <div className="w-5 h-5 rounded-md border border-slate-700 bg-slate-900 peer-checked:bg-blue-600 peer-checked:border-blue-600 transition-all" />
                <svg className="absolute top-1 left-1 w-3 h-3 text-white opacity-0 peer-checked:opacity-100 transition-opacity pointer-events-none" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                </svg>
              </div>
              <span className="text-xs font-bold text-slate-400">Remember session</span>
            </label>
          </div>

          {error && (
            <div className="p-3 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-xs font-bold text-center animate-shake">
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full py-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white font-black uppercase tracking-[0.2em] rounded-2xl shadow-xl shadow-blue-900/30 transition-all transform active:scale-[0.98] mt-4"
          >
            Unlock Dashboard
          </button>
        </form>
      </div>
    </div>
  );
};

