  const [subjects, setSubjects] = useState<Subject[]>([]);

  const batchIndex = useMemo(() => {
    if (subjects.length === 0) return 0;
    const total = subjects.reduce((acc, s) => acc + s.progress, 0);
    return Math.round(total / subjects.length);
  }, [subjects]);

  useEffect(() => {
    const savedUser = localStorage.getItem('al_2026_user');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);

      const savedSubjects = localStorage.getItem(`al_2026_subjects_${parsedUser.streamId}`);
      if (savedSubjects) {
        setSubjects(JSON.parse(savedSubjects));
      } else {
        const defaultStream = AL_STREAMS.find(s => s.id === parsedUser.streamId) || AL_STREAMS[0];
        setSubjects(defaultStream.subjects);
      }
    }
    setIsAuthLoading(false);
  }, []);

  useEffect(() => {
    if (user && subjects.length > 0) {
      localStorage.setItem(`al_2026_subjects_${user.streamId}`, JSON.stringify(subjects));
    }
  }, [subjects, user]);

  const handleLogin = (name: string, remember: boolean, streamId: string) => {
    const newUser = { name, isLoggedIn: true, streamId };
    setUser(newUser);
    if (remember) localStorage.setItem('al_2026_user', JSON.stringify(newUser));
    const stream = AL_STREAMS.find(s => s.id === streamId) || AL_STREAMS[0];
    setSubjects(stream.subjects);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('al_2026_user');
    setSubjects([]);
  };

  const toggleUnit = (subjectId: string, unitId: string) => {
    setSubjects(prev => prev.map(s => {
      if (s.id === subjectId) {
        const newUnits = s.units.map(u => 
          u.id === unitId ? { ...u, completed: !u.completed } : u
        );
        const completedCount = newUnits.filter(u => u.completed).length;
        const newProgress = Math.round((completedCount / newUnits.length) * 100);
        return { ...s, units: newUnits, progress: newProgress };
      }
      return s;
    }));
  };

  const togglePriority = (subjectId: string) => {
    setSubjects(prev => prev.map(s => 
      s.id === subjectId ? { ...s, isPrioritized: !s.isPrioritized } : s
    ));
  };

  const calculateTimeLeft = useCallback(() => {
    const now = new Date();
    const difference = currentExamDate.getTime() - now.getTime();
    if (difference > 0) {
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      });
    } else {
      setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
    }
  }, [currentExamDate]);

  useEffect(() => {
    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(timer);
  }, [calculateTimeLeft]);

  const refreshNews = async () => {
    setIsLoadingNews(true);
    try {
      const newsResult = await fetchLatestExamNews();
      setNews(newsResult);
      setLastNewsUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingNews(false);
    }
  };

  useEffect(() => {
    if (user && timeLeft.days > 0) {
      refreshNews();
    }
  }, [user, timeLeft.days]);

  if (isAuthLoading) return <div className="min-h-screen bg-slate-950 flex items-center justify-center"><div className="w-12 h-12 rounded-2xl border-4 border-blue-500/20 border-t-blue-500 animate-spin" /></div>;
  if (!user) return <LoginPage onLogin={handleLogin} />;

  const renderView = () => {
    switch(activeView) {
      case 'dashboard':
        return (
          <div className="grid md:grid-cols-12 gap-8 animate-reveal">
            <div className="md:col-span-8 space-y-8">
              <section className="text-center mb-12">
                <div className="inline-block mb-4 px-6 py-2 rounded-full bg-blue-500/10 border border-blue-500/20 animate-float shadow-[0_0_20px_rgba(59,130,246,0.1)]">
                  <span className="text-xl md:text-2xl font-black font-outfit text-transparent bg-clip-text bg-gradient-to-r from-amber-400 via-yellow-200 to-amber-500 drop-shadow-sm">
                    ✨ 3A's on the way
                  </span>
                </div>
                <h1 className="text-4xl md:text-6xl font-black font-outfit mb-6 tracking-tighter leading-tight text-white">
                  Targeting <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-cyan-400">Success.</span>
                </h1>
                <CountdownCard timeLeft={timeLeft} />
              </section>
              <ExamNews news={news} isLoading={isLoadingNews} onRefresh={refreshNews} lastUpdated={lastNewsUpdate} />
            </div>
            <div className="md:col-span-4 space-y-8">
              <div className="glass-card rounded-[2rem] p-8 border border-emerald-500/10 relative overflow-hidden">
                <h4 className="font-black text-sm uppercase tracking-widest mb-6 text-emerald-400">📊 Batch Index</h4>
                <div className="space-y-5">
                  <div className="flex justify-between items-end">
                    <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Syllabus Progress</span>
                    <span className="text-emerald-400 font-black text-2xl font-mono-tech leading-none">~{batchIndex}%</span>
                  </div>
                  <div className="w-full bg-slate-900 rounded-full h-3 p-1 border border-slate-800">
                    <div className="bg-gradient-to-r from-emerald-600 to-emerald-400 h-full rounded-full transition-all duration-1000" style={{ width: `${batchIndex}%` }} />
                  </div>
                </div>
              </div>
              <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
              <StudyGoals />
            </div>
          </div>
        );
      case 'curriculum':
        return (
          <div className="grid md:grid-cols-12 gap-8 animate-reveal">
            <div className="md:col-span-8">
              <CurriculumHub subjects={subjects} toggleUnit={toggleUnit} />
            </div>
            <div className="md:col-span-4">
              <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
            </div>
          </div>
        );
      case 'tools':
        return (
          <div className="grid md:grid-cols-12 gap-8 animate-reveal">
            <div className="md:col-span-6">
              <FocusTimer />
            </div>
            <div className="md:col-span-6">
              <ResourceVault />
            </div>
          </div>
        );
      case 'chat':
        return (
          <div className="max-w-4xl mx-auto animate-reveal">
            <AIChatBuddy />
          </div>
        );
      case 'credits':
        return (
          <div className="max-w-3xl mx-auto animate-reveal">
            <CreditsPage />
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-32 selection:bg-blue-500/30">
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden -z-10">
        <div className="absolute top-[-20%] right-[-10%] w-[60%] h-[60%] bg-blue-600/10 blur-[140px] rounded-full animate-float" />
        <div className="absolute bottom-[-10%] left-[-10%] w-[50%] h-[50%] bg-indigo-600/10 blur-[140px] rounded-full animate-float" style={{ animationDelay: '2s' }} />
      </div>

      <nav className="p-6 md:p-8 flex justify-between items-center max-w-7xl mx-auto">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => setActiveView('dashboard')}>
          <div className="w-10 h-10 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-xl flex items-center justify-center font-black text-xl shadow-xl shadow-blue-900/40 text-white transform rotate-3">A</div>
          <div className="flex flex-col">
            <span className="text-lg font-black tracking-tighter font-outfit uppercase leading-none text-white">A/L 2026</span>
            <span className="text-[10px] text-blue-400 font-bold tracking-widest uppercase">Candidate Portal</span>
          </div>
        </div>
        <div className="flex items-center gap-4">
           <div className="text-right mr-4 hidden sm:block">
            <p className="text-[10px] font-black uppercase tracking-widest text-slate-500">Welcome back,</p>
            <p className="text-xs font-bold text-white">{user.name}</p>
          </div>
          <button onClick={handleLogout} className="p-2 text-slate-500 hover:text-red-400 transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
            </svg>
          </button>
        </div>
      </nav>

      <main className="px-6 max-w-7xl mx-auto pt-4">
        {renderView()}
      </main>

      {/* Floating Bottom Navigation */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 w-full max-w-lg px-6">
        <div className="glass-card rounded-[2rem] p-2 flex items-center justify-between border-white/10 shadow-2xl backdrop-blur-2xl">
          <button 
            onClick={() => setActiveView('dashboard')}
            className={`flex-1 py-3 px-2 rounded-2xl flex flex-col items-center gap-1 transition-all ${activeView === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path d="M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z" />
            </svg>
            <span className="text-[10px] font-black uppercase tracking-tighter">Dash</span>
          </button>

          <button 
            onClick={() => setActiveView('curriculum')}
            className={`flex-1 py-3 px-2 rounded-2xl flex flex-col items-center gap-1 transition-all ${activeView === 'curriculum' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path d="M9 4.804A7.968 7.968 0 005.5 4c-1.255 0-2.443.29-3.5.804v10A7.969 7.969 0 015.5 14c1.669 0 3.218.51 4.5 1.385A7.962 7.962 0 0114.5 14c1.255 0 2.443.29 3.5.804v-10A7.968 7.968 0 0014.5 4c-1.255 0-2.443.29-3.5.804V12a1 1 0 11-2 0V4.804z" />
            </svg>
            <span className="text-[10px] font-black uppercase tracking-tighter">Study</span>
          </button>

          <button 
            onClick={() => setActiveView('tools')}
            className={`flex-1 py-3 px-2 rounded-2xl flex flex-col items-center gap-1 transition-all ${activeView === 'tools' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z" clipRule="evenodd" />
            </svg>
            <span className="text-[10px] font-black uppercase tracking-tighter">Tools</span>
          </button>

          <button 
            onClick={() => setActiveView('chat')}
            className={`flex-1 py-3 px-2 rounded-2xl flex flex-col items-center gap-1 transition-all ${activeView === 'chat' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M18 10c0 3.866-3.582 7-8 7a8.841 8.841 0 01-4.083-.98L2 17l1.338-3.123C2.493 12.767 2 11.434 2 10c0-3.866 3.582-7 8-7s8 3.134 8 7zM7 9H5v2h2V9zm8 0h-2v2h2V9zM9 9h2v2H9V9z" clipRule="evenodd" />
            </svg>
            <span className="text-[10px] font-black uppercase tracking-tighter">Buddy</span>
          </button>

          <button 
            onClick={() => setActiveView('credits')}
            className={`flex-1 py-3 px-2 rounded-2xl flex flex-col items-center gap-1 transition-all ${activeView === 'credits' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
            </svg>
            <span className="text-[10px] font-black uppercase tracking-tighter">Me</span>
          </button>
        </div>
